import PropTypes from "prop-types";
import { useState } from "react";
import { useTheme } from "../ThemeContext";

function QuestBoard({ tokens, lastFreeTaskRerollAt,
  onRerollPinned,
  pinnedQuests,
  otherQuests,
  completedIds,
  questRenderCount,
  onCompleteQuest,
  resetTimer,
  streakFreezeActive,
  onOpenNotes,
  onResetDaily,
  onHardReset
}) {
  const { t } = useTheme();
  const [showPinnedHelp, setShowPinnedHelp] = useState(false);
  const [showPinnedRerollPicker, setShowPinnedRerollPicker] = useState(false);
  const isFreePinnedReroll = !lastFreeTaskRerollAt || (Date.now() - new Date(lastFreeTaskRerollAt).getTime() >= 30 * 24 * 60 * 60 * 1000);

  return (
    <div className="lg:col-span-2 relative">
      <div className="rounded-2xl p-6" style={{ background: "var(--section-quest-bg)", border: "2px solid var(--section-quest-border)" }}>
        <div className="flex justify-between items-center mb-6">
          <div className="flex items-center gap-3">
            <span className="quest-header-icon">🧭</span>
            <h2 className="cinzel text-2xl text-transparent bg-clip-text tracking-widest" style={{ backgroundImage: "var(--quest-heading-gradient)" }}>{t.availableItems}</h2>
          </div>
          <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:gap-3 sm:justify-end mt-4">
            <button className="btn-danger bg-cyan-700 hover:bg-cyan-600 text-xs px-3 py-2 rounded-lg cinzel transition font-bold" onClick={onOpenNotes}>{t.notesButton}</button>
            <button className="btn-danger bg-yellow-700 hover:bg-yellow-600 text-xs px-3 py-2 rounded-lg cinzel transition font-bold" onClick={onResetDaily}>{t.resetDaily}</button>
            <button className="btn-danger bg-red-600 hover:bg-red-500 text-xs px-3 py-2 rounded-lg cinzel transition font-bold" onClick={onHardReset}>{t.resetProgress}</button>
          </div>
        </div>
        <div className="text-sm text-slate-300 mb-4 text-center">
          ⏰ {t.dailyResetLabel} <span className="font-bold font-mono" style={{ color: "var(--color-primary)" }}>{resetTimer}</span>
          {streakFreezeActive && (
            <span className="ml-3 inline-flex items-center gap-1 bg-cyan-900/50 border border-cyan-500/60 rounded-full px-2.5 py-0.5 text-xs text-cyan-300 cinzel">
              {t.streakProtectedBadge}
            </span>
          )}
        </div>
        {pinnedQuests.length > 0 && (
          <div className="mb-5 rounded-2xl p-4 shadow-lg" style={{ background: "var(--pinned-section-bg)", border: "2px solid var(--pinned-section-border)", boxShadow: "0 4px 24px rgba(0,0,0,0.2)" }}>
            <div className="flex items-center justify-between mb-3">
              <h3 className="cinzel text-sm uppercase tracking-[0.2em] font-bold" style={{ color: "var(--pinned-heading)" }}>{t.pinnedSection}</h3>
              <div className="flex items-center gap-2">
                <button
                  type="button"
                  onClick={() => setShowPinnedHelp(true)}
                  className="w-8 h-8 rounded-full border border-cyan-400/60 text-cyan-200 hover:bg-cyan-900/40 transition font-bold"
                  title="How pinned reroll works"
                >
                  ?
                </button>
                <button
                  type="button"
                  onClick={() => setShowPinnedRerollPicker(true)}
                  className="cinzel font-bold px-4 py-2 rounded-lg border transition-all text-[11px] flex justify-center items-center gap-1.5 whitespace-nowrap bg-gradient-to-r from-violet-700 to-purple-700 border-violet-400 text-white hover:from-violet-600 hover:to-purple-600 shadow-md shadow-violet-900/50"
                  title="Reroll a pinned quest"
                >
                  <span>рџЋІ</span>
                  Reroll
                </button>
              </div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
              {pinnedQuests.map((quest, index) => {
                const isDone = completedIds.includes(quest.id);
                return (
                  <div
                    key={`pinned-${quest.id}`}
                    className={`quest-card p-5 rounded-xl flex flex-col justify-between h-48 ${isDone ? "completed" : ""}`}
                    style={Object.assign({ background: "var(--card-pinned-bg)", border: "2px solid var(--card-pinned-border)" }, !isDone && questRenderCount === 0 ? { animationDelay: `${index * 0.1}s` } : {})}
                    onClick={(event) => onCompleteQuest(quest, event)}
                  >
                    <div className="quest-card-meta">
                      <div className="quest-category-block">
                        <p className="quest-category-value">{String(quest.category || "Uncategorized").toUpperCase()}</p>
                      </div>
                      <div className="flex items-center gap-2">
                        <span className="cinzel text-xs md:text-sm font-bold px-3 py-1.5 rounded-full" style={{ background: "var(--xp-badge-bg)", color: "var(--xp-badge-text)" }}>+{quest.xp} {t.xpLabel}</span>
                      </div>
                    </div>
                    <div className="flex-grow mt-3">
                      <h3 className="cinzel text-lg text-white font-bold mb-1">{quest.title}</h3>
                      <p className="text-slate-300 text-sm">{quest.desc}</p>
                    </div>
                    {isDone && <span className="completed-badge">{t.completedLabel}</span>}
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {otherQuests.length > 0 && (
          <div>
            <div className="flex items-center justify-between mb-3">
              <h3 className="cinzel text-xs uppercase tracking-[0.18em] text-slate-300">{t.otherSection}</h3>
              <span className="cinzel text-[11px] text-slate-500">{t.otherSectionSub}</span>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {otherQuests.map((quest, index) => {
                const isDone = completedIds.includes(quest.id);
                return (
                  <div
                    key={quest.id}
                    className={`quest-card p-5 rounded-xl flex flex-col justify-between h-48 ${isDone ? "completed" : ""}`}
                    style={!isDone && questRenderCount === 0 ? { animationDelay: `${(index + 4) * 0.1}s` } : {}}
                    onClick={(event) => onCompleteQuest(quest, event)}
                  >
                    <div className="quest-card-meta">
                      <div className="quest-category-block">
                        <p className="quest-category-value">{String(quest.category || "Uncategorized").toUpperCase()}</p>
                      </div>
                      <div className="flex items-center gap-2">
                        <span className="cinzel text-xs md:text-sm font-bold px-3 py-1.5 rounded-full" style={{ background: "var(--xp-badge-bg)", color: "var(--xp-badge-text)" }}>+{quest.xp} {t.xpLabel}</span>
                      </div>
                    </div>
                    <div className="flex-grow mt-3">
                      <h3 className="cinzel text-lg text-white font-bold mb-1">{quest.title}</h3>
                      <p className="text-slate-300 text-sm">{quest.desc}</p>
                    </div>
                    {!isDone && <div className="text-xs cinzel text-slate-400">{t.clickPrompt}</div>}
                    {isDone && <span className="completed-badge">{t.completedLabel}</span>}
                  </div>
                );
              })}
            </div>
          </div>
        )}
      </div>

      {showPinnedHelp && (
        <div className="logout-confirm-overlay" style={{ zIndex: 80 }} onClick={() => setShowPinnedHelp(false)}>
          <div className="logout-confirm-card" style={{ maxWidth: "430px" }} onClick={(event) => event.stopPropagation()}>
            <div className="text-3xl mb-3 text-center">💡</div>
            <h3 className="cinzel text-xl text-center mb-4" style={{ color: "var(--color-primary)" }}>Pinned Quest Reroll</h3>
            <div className="rounded-xl border p-4 mb-5" style={{ borderColor: "var(--color-primary-dim)", background: "rgba(15, 23, 42, 0.45)" }}>
              <p className="text-sm text-slate-200 mb-2">Your 4 pinned quests stay in your daily list.</p>
              <p className="text-sm text-slate-300 mb-2">You can reroll 1 pinned quest for free once per month.</p>
              <p className="text-sm text-slate-300">If your free reroll is used, you can reroll one for 5 tokens.</p>
            </div>
            <div className="flex justify-center">
              <button className="logout-confirm-proceed cinzel" onClick={() => setShowPinnedHelp(false)}>Got it</button>
            </div>
          </div>
        </div>
      )}

      {showPinnedRerollPicker && (
        <div className="logout-confirm-overlay" style={{ zIndex: 85 }} onClick={() => setShowPinnedRerollPicker(false)}>
          <div className="logout-confirm-card" style={{ maxWidth: "520px" }} onClick={(event) => event.stopPropagation()}>
            <div className="text-3xl mb-2 text-center">🎯</div>
            <h3 className="cinzel text-xl text-center mb-4" style={{ color: "var(--color-primary)" }}>Choose Pinned Quest To Reroll</h3>
            <div className="grid grid-cols-1 gap-2 mb-5">
              {pinnedQuests.map((quest) => (
                <button
                  key={`reroll-pinned-${quest.id}`}
                  type="button"
                  className="text-left rounded-lg border p-3 transition hover:bg-slate-800/50"
                  style={{ borderColor: "var(--card-border-idle)", background: "var(--card-bg)" }}
                  onClick={() => {
                    setShowPinnedRerollPicker(false);
                    onRerollPinned(quest.id);
                  }}
                >
                  <p className="cinzel text-sm text-slate-100 font-bold">{quest.title}</p>
                  <p className="text-xs text-slate-400 mt-1">{String(quest.category || "Uncategorized")}</p>
                </button>
              ))}
            </div>
            <div className="flex justify-center">
              <button className="logout-confirm-cancel cinzel" onClick={() => setShowPinnedRerollPicker(false)}>Cancel</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

QuestBoard.propTypes = {
  pinnedQuests: PropTypes.arrayOf(PropTypes.shape({
    id: PropTypes.number.isRequired,
    title: PropTypes.string,
    desc: PropTypes.string,
    xp: PropTypes.number,
    category: PropTypes.string,
    icon: PropTypes.string
  })).isRequired,
  otherQuests: PropTypes.arrayOf(PropTypes.shape({
    id: PropTypes.number.isRequired,
    title: PropTypes.string,
    desc: PropTypes.string,
    xp: PropTypes.number,
    category: PropTypes.string,
    icon: PropTypes.string
  })).isRequired,
  completedIds: PropTypes.arrayOf(PropTypes.number).isRequired,
  questRenderCount: PropTypes.number.isRequired,
  onCompleteQuest: PropTypes.func.isRequired,
  resetTimer: PropTypes.string.isRequired,
  streakFreezeActive: PropTypes.bool.isRequired,
  onOpenNotes: PropTypes.func.isRequired,
  onResetDaily: PropTypes.func.isRequired,
  onHardReset: PropTypes.func.isRequired,
  onRerollPinned: PropTypes.func.isRequired, tokens: PropTypes.number, lastFreeTaskRerollAt: PropTypes.string
};

export default QuestBoard;
